('ES-PROG-001', 'Essilor Progressive Varilux', 'Progressive lens with smooth transition. No-line multifocal design.', '8ed4caf5-3874-466d-9907-b1b60024642a', 'e2630b6e-b389-429e-8b47-1ad6decb7c7e', 8999, 5999, 12, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['essilor','progressive','varilux','no-line','multifocal'], ARRAY['lenses','progressive','varilux','multifocal'], '{"lens_type": "Progressive", "design": "Varilux", "index": "1.5", "uv_protection": "Yes", "material": "Plastic", "warranty": "1 Year"}', 120, 800),
('ES-BLUE-001', 'Essilor Blue Cut Computer', 'Blue cut lens for computer users. Filters harmful blue light. Reduces eye strain.', '8ed4caf5-3874-466d-9907-b1b60024642a', '42019764-4395-4437-98fa-ed23b606ac11', 3999, 2499, 12, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, true, ARRAY['essilor','blue-cut','computer','digital','blue-light','screen'], ARRAY['lenses','blue-cut','computer','digital','blue-light'], '{"lens_type": "Blue Cut", "coating": "Anti-Blue", "index": "1.5", "uv_protection": "Yes", "material": "Plastic", "warranty": "1 Year"}', 180, 1200),
('CR-HI-001', 'Crizal High Index 1.74', 'Ultra-thin high index lens for strong prescriptions. 1.74 index. Aspheric design.', '0b57a22e-c3e8-4a9c-8ff6-eecff61ce290', '3896d0d6-1159-4810-8c0b-53bdce722912', 6999, 4999, 12, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['crizal','high-index','thin','1.74','aspheric','strong'], ARRAY['lenses','high-index','thin','1.74'], '{"lens_type": "High Index", "index": "1.74", "design": "Aspheric", "uv_protection": "Yes", "material": "Plastic", "warranty": "1 Year"}', 100, 700),
