('ZE-BLUE-001', 'Zeiss Blue Light Pro', 'Premium blue light filtering lens. Crystal clear with anti-fatigue coating.', '335cf171-7af4-4e8a-aa52-808430aeac93', '42019764-4395-4437-98fa-ed23b606ac11', 4999, 3499, 12, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['zeiss','blue-light','pro','anti-fatigue','professional','clear'], ARRAY['lenses','blue-cut','pro','professional'], '{"lens_type": "Blue Light", "coating": "Anti-Fatigue", "index": "1.5", "uv_protection": "Yes", "material": "Plastic", "warranty": "1 Year"}', 90, 600),
('ES-PHOTO-001', 'Essilor Photochromic Comfort', 'Comfortable photochromic lens with fast transition. UV400 protection.', '8ed4caf5-3874-466d-9907-b1b60024642a', 'dc736477-236a-4fab-9b48-000d9fde87cd', 5999, 3999, 12, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['essilor','photochromic','comfort','fast','uv400','lightweight'], ARRAY['lenses','photochromic','comfort','fast'], '{"lens_type": "Photochromic", "design": "Comfort", "index": "1.5", "uv_protection": "UV400", "material": "Plastic", "warranty": "1 Year"}', 70, 500);
