('AC-MOIST-001', 'Acuvue Moist Daily Disposable', 'Daily disposable contact lens with Lacreon technology. 30 lenses per box. UV blocking.', 'f4cc9ac4-bafb-4124-929d-43d86adc479e', '47ceaaf6-b149-4f78-8660-47e5f530dd0f', 2499, 1499, 5, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['acuvue','daily','disposable','contact','30-lenses','lacreon','uv'], ARRAY['contact-lenses','daily','disposable','acuvue','moist'], '{"lens_type": "Daily", "technology": "Lacreon", "quantity": "30", "uv_blocking": "Yes", "material": "Hydrogel", "water_content": "58%", "warranty": "None"}', 150, 900),
