('BA-SOFT-001', 'Bausch Lomb SofLens Monthly', 'Monthly disposable aspheric contact lens. 6 lenses per box. High oxygen permeability.', '6bda1386-554a-4611-9db1-20aa432b7d3d', '2d558882-401e-4057-90e9-0cdcbff1b269', 2499, 1499, 5, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['bausch-lomb','monthly','aspheric','6-lenses','oxygen','softlens'], ARRAY['contact-lenses','monthly','bausch-lomb','soflens'], '{"lens_type": "Monthly", "design": "Aspheric", "quantity": "6", "uv_blocking": "Yes", "material": "Silicone Hydrogel", "water_content": "59%", "warranty": "None"}', 100, 700),
('BA-INFUSE-001', 'Bausch Lomb Infuse Premium', 'Premium silicone hydrogel monthly lens. 6 lenses. Ultra-high oxygen permeability.', '6bda1386-554a-4611-9db1-20aa432b7d3d', '2d558882-401e-4057-90e9-0cdcbff1b269', 3499, 2499, 5, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['bausch-lomb','monthly','silicone','hydrogel','premium','6-lenses'], ARRAY['contact-lenses','monthly','silicone-hydrogel','premium'], '{"lens_type": "Monthly", "design": "Premium", "quantity": "6", "uv_blocking": "Yes", "material": "Silicone Hydrogel", "water_content": "45%", "warranty": "None"}', 80, 500),
('JJ-COLOR-001', 'Johnson FreshLook ColorBlends', 'Colored cosmetic contact lens with 3-in-1 color technology. 2 lenses per box.', 'f4cc9ac4-bafb-4124-929d-43d86adc479e', '0d774174-9266-4e84-a8aa-a88acd2c3e3c', 1999, 1299, 5, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['johnson-johnson','colored','cosmetic','2-lenses','freshlook','colorblends'], ARRAY['contact-lenses','colored','cosmetic','freshlook'], '{"lens_type": "Colored", "technology": "3-in-1 Color", "quantity": "2", "uv_blocking": "Yes", "material": "Hydrogel", "water_content": "55%", "warranty": "None"}', 130, 1000),
('JJ-ONE-001', 'Johnson Acuvue Oasys Daily', 'Premium daily lens with HydraLuxe technology. 30 lenses. Exceptional comfort.', 'f4cc9ac4-bafb-4124-929d-43d86adc479e', '47ceaaf6-b149-4f78-8660-47e5f530dd0f', 3499, 2499, 5, ARRAY['https://images.pexels.com/photos/569388/pexels-photo-569388.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/37347/pexels-photo-37347.jpeg?auto=compress&cs=tinysrgb&w=600'], true, true, ARRAY['johnson-johnson','daily','oasys','hydraluxe','30-lenses','dry-eyes'], ARRAY['contact-lenses','daily','oasys','premium'], '{"lens_type": "Daily", "technology": "HydraLuxe", "quantity": "30", "uv_blocking": "Yes", "material": "Silicone Hydrogel", "water_content": "38%", "warranty": "None"}', 160, 1100);
